    "slug": "guide-to-vacation-deals-for-couples",
    "title": "Romantic Vacation Deals for Couples: Date Night Approved",
    "metaTitle": "Romantic Vacation Deals for Couples: Date Night Approved | VacationDeals.to",
    "metaDescription": "vacation deals for couples — real prices, honest reviews, and proven tactics to save 70-88% on resort stays. Updated for 2026.",
    "category": "segments",
    "publishDate": "2026-04-16",
